  if (process.env.FIREBASE_SERVICE_ACCOUNT) {
    try {
      const serviceAccount = JSON.parse(process.env.FIREBASE_SERVICE_ACCOUNT.trim());
      return new DocumentProcessorServiceClient({
        credentials: {
          client_email: serviceAccount.client_email,
          private_key: serviceAccount.private_key,
        },
      });
    } catch (e) {
      console.warn('⚠️ Could not parse FIREBASE_SERVICE_ACCOUNT for Document AI, using default credentials');
    }
  }
  // Fallback to default credentials (works in Vercel/GCP environments)
  return new DocumentProcessorServiceClient();
