  Future<ExtractedInvoiceData?> processInvoiceImage({
    File? imageFile,
    Uint8List? imageBytes,
  }) async {
    if (imageFile == null && imageBytes == null) {
      debugPrint('Document AI: No image file or bytes provided');
      return null;
    }

    try {
      isProcessing.value = true;
      processingMessage.value = 'analyzing_invoice'.tr;
      processingProgress.value = 0.1;

      // Step 1: Call Document AI API
      processingMessage.value = 'extracting_text'.tr;
      processingProgress.value = 0.3;

      print('🔍 Document AI: Sending invoice to backend API...');
      final result = await DocumentAIService.processInvoice(
        imageFile: imageFile,
        imageBytes: imageBytes,
      );

      processingProgress.value = 0.6;

      if (result['success'] != true) {
        print('❌ Document AI: Processing failed: ${result['error']}');
        isProcessing.value = false;
        return null;
      }

      final docAIData = result['data'];
      final fullText = docAIData['fullText'] as String? ?? '';
      final entities = docAIData['entities'] as List<dynamic>? ?? [];
      
      print('✅ Document AI: Successfully processed invoice');
      print('📊 Document AI: Extracted text length: ${fullText.length}');
      print('📊 Document AI: Found ${entities.length} entities');

      if (fullText.isEmpty) {
        print('⚠️ Document AI: No text found in image');
        isProcessing.value = false;
        return ExtractedInvoiceData.empty();
      }

      // Step 2: Parse invoice data
      processingMessage.value = 'parsing_invoice_data'.tr;
      processingProgress.value = 0.8;

      ExtractedInvoiceData extracted;
      
      if (entities.isNotEmpty) {
        // Invoice Parser format - use structured entities
        print('📋 Document AI: Using Invoice Parser entities');
        extracted = _convertDocumentAIResponse(docAIData);
      } else {
        // Document OCR format - use regex parsing on raw text
        print('📄 Document AI: Using Document OCR - parsing raw text with regex');
        // Create OCRResult from Document AI text (for compatibility with InvoiceDataExtractor)
        final ocrResult = OCRResult(
          fullText: fullText,
          blocks: [],
          lines: fullText.split('\n').map((line) => OCRTextLine(
            text: line,
            boundingBox: const Rect.fromLTWH(0, 0, 0, 0),
            confidence: 0.8,
          )).toList(),
          confidence: 0.8,
        );
        extracted = await _dataExtractor.extractInvoiceData(ocrResult);
      }
      
      extractedData.value = extracted;
      processingProgress.value = 1.0;

      isProcessing.value = false;

