  /// Convert Document AI response to ExtractedInvoiceData format
  ExtractedInvoiceData _convertDocumentAIResponse(Map<String, dynamic> docAIData) {
    final entities = docAIData['entities'] as List<dynamic>? ?? [];

    // Helper to find entity by type
    ExtractedField<T>? findEntity<T>(String type, {T Function(String)? converter}) {
      final entity = entities.firstWhere(
        (e) => e['type'] == type,
        orElse: () => null,
      );
      
      if (entity == null) return null;
      
      final value = entity['value'] as String? ?? '';
      final confidence = (entity['confidence'] as num?)?.toDouble() ?? 0.0;
      
      if (value.isEmpty) return null;
      
      T? convertedValue;
      if (converter != null) {
        try {
          convertedValue = converter(value);
        } catch (e) {
          print('⚠️ Document AI: Failed to convert $type value: $value');
          return null;
        }
      } else {
        convertedValue = value as T;
      }
      
      return ExtractedField<T>(
        value: convertedValue,
        confidence: confidence,
        rawText: value,
      );
    }

    // Extract supplier name
    final supplierName = findEntity<String>('supplier_name') ?? 
                        findEntity<String>('supplier') ??
                        ExtractedField<String>.empty();

    // Extract invoice number
    final invoiceNumber = findEntity<String>('invoice_id') ??
                         findEntity<String>('invoice_number') ??
                         ExtractedField<String>.empty();

    // Extract invoice date
    ExtractedField<DateTime> invoiceDate;
    final dateStr = findEntity<String>('invoice_date')?.value;
    if (dateStr != null) {
      try {
        // Try parsing common date formats
        final parsedDate = DateTime.parse(dateStr);
        invoiceDate = ExtractedField<DateTime>(
          value: parsedDate,
          confidence: 0.8,
          rawText: dateStr,
        );
      } catch (e) {
        // If parsing fails, use empty
        invoiceDate = ExtractedField<DateTime>.empty();
      }
    } else {
      invoiceDate = ExtractedField<DateTime>.empty();
    }

    // Extract amounts (convert to double)
    double? parseAmount(String? value) {
      if (value == null || value.isEmpty) return null;
      // Remove currency symbols and whitespace, then parse
      final cleaned = value.replaceAll(RegExp(r'[^\d.,-]'), '').replaceAll(',', '');
      try {
        return double.parse(cleaned);
      } catch (e) {
        return null;
      }
    }

    final totalAmountStr = findEntity<String>('total_amount')?.value ??
                          findEntity<String>('total')?.value;
    final grossAmount = parseAmount(totalAmountStr);
    
    final netAmountStr = findEntity<String>('net_amount')?.value ??
                        findEntity<String>('net')?.value;
    final netAmount = parseAmount(netAmountStr);
    
    final taxAmountStr = findEntity<String>('tax_amount')?.value ??
                        findEntity<String>('vat_amount')?.value;
    final vatAmount = parseAmount(taxAmountStr);

    // Calculate overall confidence
    final confidences = <double>[
      supplierName.confidence,
      invoiceNumber.confidence,
      invoiceDate.confidence,
    ];
    if (grossAmount != null) confidences.add(0.8);
    if (netAmount != null) confidences.add(0.8);
    if (vatAmount != null) confidences.add(0.8);
    
    final overallConfidence = confidences.isEmpty 
        ? 0.0 
        : confidences.reduce((a, b) => a + b) / confidences.length;

    return ExtractedInvoiceData(
      supplierName: supplierName,
      invoiceNumber: invoiceNumber,
      invoiceDate: invoiceDate,
      netAmount: netAmount,
      vatAmount: vatAmount,
      grossAmount: grossAmount,
      overallConfidence: overallConfidence,
    );
  }

